// Normalise Instantly + Resend events to a common shape, then forward.
const e = $json;
const kind = e.type || (e.event && e.event.type);
let event;
if (kind?.startsWith('email.bounced')) event = { type: 'email.bounced', message_id: e.message_id || e.data?.email_id, email: e.email || e.data?.to?.[0] };
else if (kind?.startsWith('email.replied')) event = { type: 'email.replied', message_id: e.message_id || e.data?.email_id, email: e.email || e.data?.from };
else if (kind?.startsWith('email.opened')) event = { type: 'email.opened', message_id: e.message_id || e.data?.email_id };
else if (kind?.startsWith('email.clicked')) event = { type: 'email.clicked', message_id: e.message_id || e.data?.email_id };
else return [];
return [{ json: event }];
